light.aceEditor:
.ace_editor {
   border: 1px solid #d4d5d7;
   border-radius: 5px;
 }

 .ace-graylog {
   background-color: #fff;
   color: #67717f;

   &.ace_multiselect .ace_selection.ace_start {
     box-shadow: 0 0 3px 0 #fff;
   }

   .ace_gutter {
     background: #d7dce4;
     color: #67717f;
   }

   .ace_print-margin {
     width: 1px;
     background: #d7dce4;
   }

   .ace_cursor {
     color: #b5bfcd;
   }

   .ace_marker-layer {
     .ace_selection {
       background: #bfc0c3;
     }

     .ace_step {
       background: rgb(255 255 0);
     }

     .ace_bracket {
       margin: -1px 0 0 -1px;
       border: 1px solid #bfc0c3;
     }

     .ace_selected-word {
       border: 1px solid #a9abaf;
     }

     .ace_active-line {
       background: #c7ced9;
     }
   }

   .ace_gutter-active-line {
     background-color: #c7ced9;
   }

   .ace_invisible {
     color: #bfc0c3;
   }

   .ace_keyword,
   .ace_meta,
   .ace_storage,
   .ace_storage.ace_type,
   .ace_support.ace_type {
     color: #578dcc;
   }

   .ace_keyword.ace_operator {
     color: #446fa0;
   }

   .ace_constant.ace_character,
   .ace_constant.ace_language,
   .ace_constant.ace_numeric,
   .ace_keyword.ace_other.ace_unit,
   .ace_support.ace_constant,
   .ace_variable.ace_parameter {
     color: #525c69;
   }

   .ace_constant.ace_other {
     color: #798494;
   }

   .ace_invalid {
     color: #fff;
     background-color: #f08d8d;
   }

   .ace_invalid.ace_deprecated {
     color: #fff;
     background-color: #697586;
   }

   .ace_fold {
     background-color: #578dcc;
     border-color: #67717f;
   }

   .ace_entity.ace_name.ace_function,
   .ace_support.ace_function,
   .ace_variable {
     color: #578dcc;
   }

   .ace_support.ace_class,
   .ace_support.ace_type {
     color: #bbaf4e;
   }

   .ace_heading,
   .ace_markup.ace_heading,
   .ace_string {
     color: #638c43;
   }

   .ace_entity.ace_name.ace_tag,
   .ace_entity.ace_other.ace_attribute-name,
   .ace_meta.ace_tag,
   .ace_string.ace_regexp,
   .ace_variable {
     color: #f08d8d;
   }

   .ace_comment {
     color: #8894a7;
   }
 }

